import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class PaypalService {
  private clientId: string;
  private clientSecret: string;
  private mode: string; // 'sandbox' ou 'live'
  private apiUrl: string;

  constructor(private configService: ConfigService) {
    this.clientId = this.configService.get('PAYPAL_CLIENT_ID');
    this.clientSecret = this.configService.get('PAYPAL_SECRET');
    this.mode = this.configService.get('PAYPAL_MODE', 'sandbox');
    this.apiUrl = this.mode === 'live' 
      ? 'https://api-m.paypal.com' 
      : 'https://api-m.sandbox.paypal.com';
  }
}
