import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';

async getAccessToken(): Promise<string> {
  const auth = Buffer.from(`${this.clientId}:${this.clientSecret}`).toString('base64');
  const response = await firstValueFrom(
    this.httpService.post(`${this.apiUrl}/v1/oauth2/token`,
      'grant_type=client_credentials',
      {
        headers: {
          Authorization: `Basic ${auth}`,
          'Content-Type': 'application/x-www-form-urlencoded',
        },
      }
    )
  );
  return response.data.access_token;
}

async createOrder(amount: number, currency: string, orderId: number): Promise<string> {
  const accessToken = await this.getAccessToken();
  const response = await firstValueFrom(
    this.httpService.post(
      `${this.apiUrl}/v2/checkout/orders`,
      {
        intent: 'CAPTURE',
        purchase_units: [
          {
            reference_id: `ORDER_${orderId}`,
            amount: {
              currency_code: currency,
              value: amount.toFixed(2),
              breakdown: {
                item_total: { currency_code: currency, value: amount.toFixed(2) },
              },
            },
            description: `Commande #${orderId} sur MarketCamer`,
          },
        ],
        application_context: {
          brand_name: 'MarketCamer',
          landing_page: 'LOGIN',
          user_action: 'PAY_NOW',
          return_url: `${this.configService.get('APP_URL')}/paypal/success`,
          cancel_url: `${this.configService.get('APP_URL')}/paypal/cancel`,
        },
      },
      {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'Content-Type': 'application/json',
        },
      }
    )
  );
  const approvalUrl = response.data.links.find(link => link.rel === 'approve').href;
  return approvalUrl; // URL pour rediriger l'utilisateur vers PayPal
}
