async captureOrder(paypalOrderId: string): Promise<any> {
  const accessToken = await this.getAccessToken();
  const response = await firstValueFrom(
    this.httpService.post(
      `${this.apiUrl}/v2/checkout/orders/${paypalOrderId}/capture`,
      {},
      {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          'Content-Type': 'application/json',
        },
      }
    )
  );
  return response.data; // Contient le statut 'COMPLETED', l'ID de capture, etc.
}

// paypal.controller.ts
@Get('success')
async paypalSuccess(@Query('token') token: string, @Query('PayerID') payerId: string) {
  // token correspond à l'ID de l'order PayPal
  const captureResult = await this.paypalService.captureOrder(token);

  if (captureResult.status === 'COMPLETED') {
    // Mettre à jour la commande en base de données (statut -> PAID)
    const referenceId = captureResult.purchase_units[0].reference_id;
    const internalOrderId = referenceId.split('_')[1];
    await this.orderService.markAsPaid(parseInt(internalOrderId), captureResult.id);
    return { message: 'Paiement réussi', orderId: internalOrderId };
  } else {
    throw new BadRequestException('Le paiement n\'a pas pu être capturé');
  }
}
